const generateCluster = (count, meanX, meanY, stdDev, color, label) => {
  const x = [];
  const y = [];
  for (let i = 0; i < count; i++) {
    // Box-Muller transform for normal distribution
    let u = 0, v = 0;
    while(u === 0) u = Math.random();
    while(v === 0) v = Math.random();
    const z0 = Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);

    u = 0, v = 0;
    while(u === 0) u = Math.random();
    while(v === 0) v = Math.random();
    const z1 = Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);

    x.push(meanX + z0 * stdDev);
    y.push(meanY + z1 * stdDev);
  }
  return {
    x: x,
    y: y,
    mode: 'markers',
    type: 'scatter',
    name: label,
    marker: {
      size: 8,
      color: color,
      opacity: 0.6,
      line: {
        width: 1,
        color: '#1e293b'
      }
    }
  };
};

const traces = [
  generateCluster(300, 2, 3, 0.75, '#3b82f6', 'Alpha Segment'),
  generateCluster(250, -2, -1, 1.2, '#ef4444', 'Beta Segment'),
  generateCluster(200, 4, -4, 0.5, '#10b981', 'Gamma Segment'),
  generateCluster(150, -5, 5, 0.9, '#f59e0b', 'Delta Segment')
];

return traces;
